// LESSON: Reference Page 1 - Streams.
// You will learn: Build stream pipelines with filter, map, collect, reduce, and grouping.
class Prog2Reference438 {
  // EXEMPEL 1: filter valjer vilka element som far ga vidare.
  static java.util.List<String> adultNames(java.util.List<Person> people) {
    return people.stream().filter(person -> person.age >= 18).map(person -> person.name).sorted().collect(java.util.stream.Collectors.toList());
  }
  static class Person {
    final String name;
    final int age;
    Person(String name, int age) { this.name = name; this.age = age; }
  }
  // EXEMPEL 2: count och anyMatch ar terminala operationer.
  static boolean hasShortName(java.util.List<String> names) {
    long count = names.stream().filter(name -> name.length() <= 3).count();
    return count > 0 && names.stream().anyMatch(name -> name.startsWith("A"));
  }
  // EXEMPEL 3: mapToInt och sum passar numeriska berakningar.
  static int totalLength(java.util.List<String> names) {
    return names.stream().mapToInt(name -> name.length()).sum();
  }
}
